{"version":3,"file":"dashboard.min.js","sources":["../src/dashboard.js"],"sourcesContent":["// This file is part of Moodle - http://moodle.org/\n//\n// Moodle is free software: you can redistribute it and/or modify\n// it under the terms of the GNU General Public License as published by\n// the Free Software Foundation, either version 3 of the License, or\n// (at your option) any later version.\n//\n// Moodle is distributed in the hope that it will be useful,\n// but WITHOUT ANY WARRANTY; without even the implied warranty of\n// MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the\n// GNU General Public License for more details.\n//\n// You should have received a copy of the GNU General Public License\n// along with Moodle.  If not, see <http://www.gnu.org/licenses/>.\n\n/**\n * Dashboard module — loads the data table asynchronously and initialises DataTables.\n *\n * @module     report_dashboard/dashboard\n * @copyright  2025 Andrew Rowatt <A.J.Rowatt@massey.ac.nz>\n * @license    http://www.gnu.org/copyleft/gpl.html GNU GPL v3 or later\n */\nimport $ from 'jquery';\nimport DataTable from 'report_dashboard/dataTables';\nimport 'report_dashboard/dataTables.bootstrap4';\nimport 'report_dashboard/dataTables.select';\nimport 'report_dashboard/dataTables.buttons';\nimport 'report_dashboard/buttons.bootstrap4';\nimport 'report_dashboard/buttons.html5';\nimport {setUserPreference} from 'core_user/repository';\n\nexport const init = (courseid, hiddencmids) => {\n    $(function() {\n        window.console.log('Report dashboard initialising'); // Debug log to confirm script is running\n\n        // Load the dashboard table asynchronously.\n        fetch(M.cfg.wwwroot + '/report/dashboard/dashboard.php?id=' + courseid)\n            .then(response => response.text())\n            .then(html => {\n                // Insert the table HTML into the dashboard container.\n                document.querySelector('.dashboard_container').insertAdjacentHTML('beforeend', html);\n\n                initDashboard(hiddencmids);\n                return true;\n            })\n            .catch(error => {\n                window.console.error('Failed to load dashboard:', error);\n            });\n    });\n};\n\n/**\n * Initialise DataTables and all filter logic after the table has been loaded.\n *\n * @param {number[]} hiddencmids Array of currently hidden cmids\n */\nfunction initDashboard(hiddencmids) {\n    var table = new DataTable('#report_dashboard_dashboard',\n        {\n            orderCellsTop: true,\n            responsive: false,\n            autoWidth: false,\n            paging: false,\n            layout: {\n                topStart: 'info',\n                topEnd: null,\n                bottomStart: {\n                    buttons: [\n                        {\n                            extend: 'excelHtml5',\n                            text: 'Export to Excel',\n                        },\n                        {\n                            text: 'Copy email addresses of selected students',\n                            className: 'customButton customButtonCopyEmailAddress btn btn-secondary',\n                            action: function(e, dt) {\n                                let s = '';\n                                // eslint-disable-next-line array-callback-return, no-unused-vars\n                                dt.rows({selected: true}).every((rowIdx, tableLoop, rowLoop) => {\n                                    const node = this.cell(rowIdx, 2).node();\n                                    s += node.dataset.formattedEmail + ';';\n                                });\n\n                                navigator.clipboard.writeText(s);\n                            }\n                        },\n                        {\n                            text: 'Create email to selected students...',\n                            className: 'customButton customButtonCreateEmail btn btn-secondary',\n                            action: function(e, dt) {\n                                var s = '';\n                                // eslint-disable-next-line array-callback-return, no-unused-vars\n                                dt.rows({selected: true}).every((rowIdx, tableLoop, rowLoop) => {\n                                    const node = this.cell(rowIdx, 2).node();\n                                    s += node.dataset.formattedEmail + ';';\n                                });\n                                location.href = `mailto:?bcc=${encodeURIComponent(s)}`;\n                            }\n                        },\n                        {\n                            text: 'Clear selected rows',\n                            className: 'customButton customButtonClearSelectedRows btn btn-secondary',\n                            action: function(e, dt) {\n                                dt.rows({selected: true}).deselect();\n                            }\n                        }\n                    ]\n                }\n            },\n            columnDefs: [\n                {\n                    orderable: false,\n                    render: DataTable.render.select(),\n                    targets: 0\n                }\n            ],\n            select: {\n                style: 'multi',\n                headerCheckbox: 'select-page'\n            },\n            order: [[1, 'asc']], /* Removes order symbol from column 0 (checkbox) */\n            initComplete: function() {\n                // Make any adjustments to the columns when the table is initialised.\n                this.api().columns([2]).visible(false); // Hide email column\n\n                // Reveal the table and hide the skeleton loader.\n                document.querySelector('.dashboard_container').classList.add('dt-ready');\n\n                // Enable widgets that were disabled while the table was loading.\n                document.getElementById('report_dashboard_fontsize').disabled = false;\n                document.querySelectorAll('.dashboard_container button[disabled]').forEach(btn => {\n                    btn.disabled = false;\n                });\n            }\n        }\n    );\n\n    document.getElementById('report_dashboard_fontsize').addEventListener('change', function() {\n        const dashboardTable = document.getElementById('report_dashboard_dashboard');\n        dashboardTable.className = dashboardTable.className.replace(/\\bsz-\\d+\\b/, 'sz-' + this.value);\n        setUserPreference('report_dashboard_fontsize', this.value);\n    });\n\n    updateFilterCounts(true);\n\n    table.on('draw', function() {\n        updateFilterCounts(false);\n    });\n\n    /* eslint complexity: [\"error\", {\"max\": 30 }] */\n    $.fn.dataTable.ext.search.push(function(settings, data, dataIndex) {\n        let row = $(table.row(dataIndex).node());\n\n        /*\n            Last access filter\n        */\n        let lastaccessed = document.querySelector(\"input[name='lastaccessed']:checked\");\n        document.querySelector(\"#lastaccessed > button > span\").textContent = lastaccessed.dataset.label;\n\n        if (lastaccessed.value != \"all\") {\n            if (row.find(`td.tc_lastaccessed span[data-filter-category=\"${lastaccessed.value}\"]`).length == 0) {\n                return false;\n            }\n        }\n\n        /*\n            Groups filter\n        */\n        let groupmatch = false; // By default we assume that no groups are matching\n        let groups = document.querySelectorAll(\"input[name='groups']\");\n        let groupschecked = document.querySelectorAll(\"input[name='groups']:checked\").length;\n        let anygroupunchecked = groups.length != groupschecked;\n\n        let dropdownlabel = \"Unknown\"; // Default label for the dropdown\n\n        for (const group of groups) {\n            if (group.checked) {\n                dropdownlabel = group.dataset.label;\n\n                if (row.find(`td.tc_groups span[data-filter-category=\"${group.value}\"]`).length > 0) {\n                    groupmatch = true;\n                    break;\n                }\n            }\n        }\n\n        document.getElementById(\"group_select_all\").disabled = !anygroupunchecked;\n        document.getElementById(\"group_select_none\").disabled = groupschecked == 0;\n\n\n        if (groupschecked == 0) {\n            dropdownlabel = \"None\";\n        } else if (groupschecked == 1) {\n            // The dropdownlabel will be set by code above.\n        } else if (anygroupunchecked) {\n            dropdownlabel = \"Multiple Groups\";\n        } else {\n            dropdownlabel = \"All\";\n        }\n\n        document.querySelector(\"#group > button > span\").textContent = dropdownlabel;\n\n        if (!groupmatch) {\n            return false;\n        }\n\n        /*\n            Late assessments filter\n        */\n        let lateassessments = document.querySelector(\"input[name='lateassessments']:checked\");\n        document.querySelector(\"#lateassessments > button > span\").textContent = lateassessments.dataset.label;\n\n        if (lateassessments.value != \"all\") {\n            if (row.find(`td.tc_lateassessments span[data-filter-category=\"${lateassessments.value}\"]`).length == 0) {\n                return false;\n            }\n        }\n\n        /*\n            Early engagements filter\n        */\n\n        let earlyengagementFilters = document.querySelectorAll(\".earlyengagement_filter\");\n\n        for (const earlyengagementFilter of earlyengagementFilters) {\n            let id = earlyengagementFilter.dataset.earlyengagementid;\n            let itemMatch = false;\n            let items = document.querySelectorAll(`input[name='earlyengagement${id}_filter']`);\n            let itemsChecked = document.querySelectorAll(`input[name='earlyengagement${id}_filter']:checked`).length;\n            let anyUnchecked = items.length != itemsChecked;\n\n            let dropdownlabel = \"Unknown\"; // Default label for the dropdown\n\n            for (const item of items) {\n                if (item.checked) {\n                    dropdownlabel = item.dataset.label;\n\n                    // eslint-disable-next-line max-len\n                    if (row.find(`td.tc_earlyengagement.earlyengagement${id} span[data-filter-category=\"${item.value}\"]`).length > 0) {\n                        itemMatch = true;\n                        break;\n                    }\n                }\n            }\n\n            document.getElementById(`earlyengagement${id}_select_all`).disabled = !anyUnchecked;\n            document.getElementById(`earlyengagement${id}_select_none`).disabled = itemsChecked == 0;\n\n            if (itemsChecked == 0) {\n                dropdownlabel = \"None\";\n            } else if (itemsChecked == 1) {\n                // The dropdownlabel will be set by code above.\n            } else if (anyUnchecked) {\n                dropdownlabel = \"Multiple criteria\";\n            } else {\n                dropdownlabel = \"All\";\n            }\n\n            document.querySelector(`#earlyengagement${id} > button > span`).textContent = dropdownlabel;\n\n            if (!itemMatch) {\n                return false;\n            }\n        }\n\n        /*\n            Assessments filter\n        */\n\n        let assessmentFilters = document.querySelectorAll(\".assessment_filter\");\n\n        for (const assessmentFilter of assessmentFilters) {\n            let id = assessmentFilter.dataset.assessmentid;\n            let itemMatch = false;\n            let items = document.querySelectorAll(`label:not([data-filter-total=\"0\"]) > input[name='assessment${id}_filter']`);\n            // eslint-disable-next-line max-len\n            let itemsChecked = document.querySelectorAll(`label:not([data-filter-total=\"0\"]) > input[name='assessment${id}_filter']:checked`).length;\n            let anyUnchecked = items.length != itemsChecked;\n\n            let dropdownlabel = \"Unknown\"; // Default label for the dropdown\n\n            for (const item of items) {\n                if (item.checked) {\n                    dropdownlabel = item.dataset.label;\n\n                    if (row.find(`td.tc_assessment.assessment${id} span[data-filter-category=\"${item.value}\"]`).length > 0) {\n                        itemMatch = true;\n                        break;\n                    }\n                }\n            }\n\n            document.getElementById(`assessment${id}_select_all`).disabled = !anyUnchecked;\n            document.getElementById(`assessment${id}_select_none`).disabled = itemsChecked == 0;\n\n            if (itemsChecked == 0) {\n                dropdownlabel = \"None\";\n            } else if (itemsChecked == 1) {\n                // The dropdownlabel will be set by code above.\n            } else if (anyUnchecked) {\n                dropdownlabel = \"Multiple criteria\";\n            } else {\n                dropdownlabel = \"All\";\n            }\n\n            document.querySelector(`#assessment${id} > button > span`).textContent = dropdownlabel;\n\n            if (!itemMatch) {\n                return false;\n            }\n        }\n\n        return true;\n    });\n\n    $(\"#name_filter\").on(\"input\", function() {\n        // ... Modern search approach\n        table.columns(1).search(this.value).draw();\n    });\n\n    $(\"tr.filters .earlyengagement_filter .dropdown-menu\").on(\"click\", (e) => {\n        let id = e.currentTarget.dataset.earlyengagementid;\n\n        switch (e.target.id) {\n            case `earlyengagement${id}_select_all`:\n                document.querySelectorAll(`input[name='earlyengagement${id}_filter']`).forEach((item) => {\n                    if (!item.disabled) {\n                        item.checked = true;\n                    }\n                });\n                break;\n            case `earlyengagement${id}_select_none`:\n                document.querySelectorAll(`input[name='earlyengagement${id}_filter']`).forEach((item) => {\n                    item.checked = false;\n                });\n                break;\n        }\n    });\n\n    $(\"tr.filters .assessment_filter .dropdown-menu\").on(\"click\", (e) => {\n        let id = e.currentTarget.dataset.assessmentid;\n\n        switch (e.target.id) {\n            case `assessment${id}_select_all`:\n                document.querySelectorAll(`input[name='assessment${id}_filter']`).forEach((item) => {\n                    if (!item.disabled) {\n                        item.checked = true;\n                    }\n                });\n                break;\n            case `assessment${id}_select_none`:\n                document.querySelectorAll(`input[name='assessment${id}_filter']`).forEach((item) => {\n                    item.checked = false;\n                });\n                break;\n        }\n    });\n\n    $(\"tr.filters .dropdown-menu\").on(\"click\", (e) => {\n        /*\n            Special handling cases for filters\n        */\n\n        switch (e.target.id) {\n            case \"group_select_all\":\n                document.querySelectorAll(\"input[name='groups']\").forEach((group) => {\n                    if (!group.disabled) {\n                        group.checked = true;\n                    }\n                });\n\n                break;\n            case \"group_select_none\":\n                document.querySelectorAll(\"input[name='groups']\").forEach((group) => {\n                    group.checked = false;\n                });\n                break;\n        }\n\n        table.draw();\n    });\n\n    // Hide column buttons — hide the column instantly and save preference via AJAX.\n    document.querySelectorAll('.hide-column-btn').forEach(btn => {\n        btn.addEventListener('click', function() {\n            const cmid = parseInt(this.dataset.cmid);\n            const name = this.dataset.name;\n            const type = this.dataset.type;\n            const th = this.closest('th');\n            // Use DataTables column(node) to get the correct index regardless of hidden columns.\n            const col = table.column(th);\n\n            col.visible(false);\n            hiddencmids.push(cmid);\n            setUserPreference('report_dashboard_hidden_cmids', JSON.stringify(hiddencmids));\n\n            // Create a dynamic \"Show\" button in the show/hide container.\n            const showLabel = type === 'assessment' ? 'Show assessment' : 'Show early engagement activity';\n            const showBtn = document.createElement('button');\n            showBtn.type = 'button';\n            showBtn.className = 'btn btn-outline-primary btn-sm';\n            showBtn.innerHTML = `<i class=\"fa fa-eye\" aria-hidden=\"true\"></i> ${showLabel} ${name}`;\n            showBtn.addEventListener('click', function() {\n                col.visible(true);\n                hiddencmids = hiddencmids.filter(id => id !== cmid);\n                setUserPreference('report_dashboard_hidden_cmids', JSON.stringify(hiddencmids));\n                this.remove();\n            });\n            document.getElementById('report_dashboard_showhide').appendChild(showBtn);\n        });\n    });\n\n    /**\n     * Update counts for filters\n     *\n     * @param {boolean} firstTime\n     */\n    function updateFilterCounts(firstTime) {\n        $('[data-filter-count] > input').each(function(i, e) {\n            let filter = e.value;\n            let scope = e.name.replace(\"_filter\", \"\");\n\n            let count = $(`td.${scope} [data-filter-category=\"${filter}\"]`).length;\n            e.parentElement.dataset.filterCount = count;\n            if (firstTime) {\n                e.parentElement.dataset.filterTotal = count;\n                e.disabled = !count;\n                if (!count) {\n                    e.checked = false;\n                }\n                e.parentElement.classList.toggle(\"text-muted\", !count);\n            }\n        });\n    }\n}\n"],"names":["courseid","hiddencmids","window","console","log","fetch","M","cfg","wwwroot","then","response","text","html","document","querySelector","insertAdjacentHTML","table","DataTable","orderCellsTop","responsive","autoWidth","paging","layout","topStart","topEnd","bottomStart","buttons","extend","className","action","e","dt","s","rows","selected","every","rowIdx","tableLoop","rowLoop","node","this","cell","dataset","formattedEmail","navigator","clipboard","writeText","location","href","encodeURIComponent","deselect","columnDefs","orderable","render","select","targets","style","headerCheckbox","order","initComplete","api","columns","visible","classList","add","getElementById","disabled","querySelectorAll","forEach","btn","updateFilterCounts","firstTime","each","i","filter","value","scope","name","replace","count","length","parentElement","filterCount","filterTotal","checked","toggle","addEventListener","dashboardTable","on","fn","dataTable","ext","search","push","settings","data","dataIndex","row","lastaccessed","textContent","label","find","groupmatch","groups","groupschecked","anygroupunchecked","dropdownlabel","group","lateassessments","earlyengagementFilters","earlyengagementFilter","id","earlyengagementid","itemMatch","items","itemsChecked","anyUnchecked","item","assessmentFilters","assessmentFilter","assessmentid","draw","currentTarget","target","cmid","parseInt","type","th","closest","col","column","JSON","stringify","showLabel","showBtn","createElement","innerHTML","remove","appendChild","initDashboard","catch","error"],"mappings":";;;;;;;wLA+BoB,CAACA,SAAUC,oCACzB,WACEC,OAAOC,QAAQC,IAAI,iCAGnBC,MAAMC,EAAEC,IAAIC,QAAU,sCAAwCR,UACzDS,MAAKC,UAAYA,SAASC,SAC1BF,MAAKG,OAEFC,SAASC,cAAc,wBAAwBC,mBAAmB,YAAaH,eAgBxEX,iBACfe,MAAQ,IAAIC,oBAAU,8BACtB,CACIC,eAAe,EACfC,YAAY,EACZC,WAAW,EACXC,QAAQ,EACRC,OAAQ,CACJC,SAAU,OACVC,OAAQ,KACRC,YAAa,CACTC,QAAS,CACL,CACIC,OAAQ,aACRhB,KAAM,mBAEV,CACIA,KAAM,4CACNiB,UAAW,8DACXC,OAAQ,SAASC,EAAGC,QACZC,EAAI,GAERD,GAAGE,KAAK,CAACC,UAAU,IAAOC,OAAM,CAACC,OAAQC,UAAWC,iBAC1CC,KAAOC,KAAKC,KAAKL,OAAQ,GAAGG,OAClCP,GAAKO,KAAKG,QAAQC,eAAiB,OAGvCC,UAAUC,UAAUC,UAAUd,KAGtC,CACIrB,KAAM,uCACNiB,UAAW,yDACXC,OAAQ,SAASC,EAAGC,QACZC,EAAI,GAERD,GAAGE,KAAK,CAACC,UAAU,IAAOC,OAAM,CAACC,OAAQC,UAAWC,iBAC1CC,KAAOC,KAAKC,KAAKL,OAAQ,GAAGG,OAClCP,GAAKO,KAAKG,QAAQC,eAAiB,OAEvCI,SAASC,2BAAsBC,mBAAmBjB,MAG1D,CACIrB,KAAM,sBACNiB,UAAW,+DACXC,OAAQ,SAASC,EAAGC,IAChBA,GAAGE,KAAK,CAACC,UAAU,IAAOgB,gBAM9CC,WAAY,CACR,CACIC,WAAW,EACXC,OAAQpC,oBAAUoC,OAAOC,SACzBC,QAAS,IAGjBD,OAAQ,CACJE,MAAO,QACPC,eAAgB,eAEpBC,MAAO,CAAC,CAAC,EAAG,QACZC,aAAc,gBAELC,MAAMC,QAAQ,CAAC,IAAIC,SAAQ,GAGhCjD,SAASC,cAAc,wBAAwBiD,UAAUC,IAAI,YAG7DnD,SAASoD,eAAe,6BAA6BC,UAAW,EAChErD,SAASsD,iBAAiB,yCAAyCC,SAAQC,MACvEA,IAAIH,UAAW,iBA8RtBI,mBAAmBC,+BACtB,+BAA+BC,MAAK,SAASC,EAAG3C,OAC1C4C,OAAS5C,EAAE6C,MACXC,MAAQ9C,EAAE+C,KAAKC,QAAQ,UAAW,IAElCC,OAAQ,gCAAQH,yCAAgCF,cAAYM,OAChElD,EAAEmD,cAAcvC,QAAQwC,YAAcH,MAClCR,YACAzC,EAAEmD,cAAcvC,QAAQyC,YAAcJ,MACtCjD,EAAEoC,UAAYa,MACTA,QACDjD,EAAEsD,SAAU,GAEhBtD,EAAEmD,cAAclB,UAAUsB,OAAO,cAAeN,WArS5DlE,SAASoD,eAAe,6BAA6BqB,iBAAiB,UAAU,iBACtEC,eAAiB1E,SAASoD,eAAe,8BAC/CsB,eAAe3D,UAAY2D,eAAe3D,UAAUkD,QAAQ,aAAc,MAAQtC,KAAKmC,yCACrE,4BAA6BnC,KAAKmC,UAGxDL,oBAAmB,GAEnBtD,MAAMwE,GAAG,QAAQ,WACblB,oBAAmB,sBAIrBmB,GAAGC,UAAUC,IAAIC,OAAOC,MAAK,SAASC,SAAUC,KAAMC,eAChDC,KAAM,mBAAEjF,MAAMiF,IAAID,WAAWzD,QAK7B2D,aAAerF,SAASC,cAAc,yCAC1CD,SAASC,cAAc,iCAAiCqF,YAAcD,aAAaxD,QAAQ0D,MAEjE,OAAtBF,aAAavB,OACmF,GAA5FsB,IAAII,6DAAsDH,aAAavB,aAAWK,cAC3E,MAOXsB,YAAa,EACbC,OAAS1F,SAASsD,iBAAiB,wBACnCqC,cAAgB3F,SAASsD,iBAAiB,gCAAgCa,OAC1EyB,kBAAoBF,OAAOvB,QAAUwB,cAErCE,cAAgB,cAEf,MAAMC,SAASJ,UACZI,MAAMvB,UACNsB,cAAgBC,MAAMjE,QAAQ0D,MAE1BH,IAAII,uDAAgDM,MAAMhC,aAAWK,OAAS,GAAG,CACjFsB,YAAa,WAMzBzF,SAASoD,eAAe,oBAAoBC,UAAYuC,kBACxD5F,SAASoD,eAAe,qBAAqBC,SAA4B,GAAjBsC,cAGnC,GAAjBA,cACAE,cAAgB,OACQ,GAAjBF,gBAGPE,cADOD,kBACS,kBAEA,OAGpB5F,SAASC,cAAc,0BAA0BqF,YAAcO,eAE1DJ,kBACM,MAMPM,gBAAkB/F,SAASC,cAAc,4CAC7CD,SAASC,cAAc,oCAAoCqF,YAAcS,gBAAgBlE,QAAQ0D,MAEpE,OAAzBQ,gBAAgBjC,OACsF,GAAlGsB,IAAII,gEAAyDO,gBAAgBjC,aAAWK,cACjF,MAQX6B,uBAAyBhG,SAASsD,iBAAiB,+BAElD,MAAM2C,yBAAyBD,uBAAwB,KACpDE,GAAKD,sBAAsBpE,QAAQsE,kBACnCC,WAAY,EACZC,MAAQrG,SAASsD,sDAA+C4C,iBAChEI,aAAetG,SAASsD,sDAA+C4C,yBAAuB/B,OAC9FoC,aAAeF,MAAMlC,QAAUmC,aAE/BT,cAAgB,cAEf,MAAMW,QAAQH,SACXG,KAAKjC,UACLsB,cAAgBW,KAAK3E,QAAQ0D,MAGzBH,IAAII,oDAA6CU,0CAAiCM,KAAK1C,aAAWK,OAAS,GAAG,CAC9GiC,WAAY,WAMxBpG,SAASoD,wCAAiC8C,mBAAiB7C,UAAYkD,aACvEvG,SAASoD,wCAAiC8C,oBAAkB7C,SAA2B,GAAhBiD,aAEnD,GAAhBA,aACAT,cAAgB,OACO,GAAhBS,eAGPT,cADOU,aACS,oBAEA,OAGpBvG,SAASC,wCAAiCiG,wBAAsBZ,YAAcO,eAEzEO,iBACM,MAQXK,kBAAoBzG,SAASsD,iBAAiB,0BAE7C,MAAMoD,oBAAoBD,kBAAmB,KAC1CP,GAAKQ,iBAAiB7E,QAAQ8E,aAC9BP,WAAY,EACZC,MAAQrG,SAASsD,uFAA+E4C,iBAEhGI,aAAetG,SAASsD,uFAA+E4C,yBAAuB/B,OAC9HoC,aAAeF,MAAMlC,QAAUmC,aAE/BT,cAAgB,cAEf,MAAMW,QAAQH,SACXG,KAAKjC,UACLsB,cAAgBW,KAAK3E,QAAQ0D,MAEzBH,IAAII,0CAAmCU,0CAAiCM,KAAK1C,aAAWK,OAAS,GAAG,CACpGiC,WAAY,WAMxBpG,SAASoD,mCAA4B8C,mBAAiB7C,UAAYkD,aAClEvG,SAASoD,mCAA4B8C,oBAAkB7C,SAA2B,GAAhBiD,aAE9C,GAAhBA,aACAT,cAAgB,OACO,GAAhBS,eAGPT,cADOU,aACS,oBAEA,OAGpBvG,SAASC,mCAA4BiG,wBAAsBZ,YAAcO,eAEpEO,iBACM,SAIR,yBAGT,gBAAgBzB,GAAG,SAAS,WAE1BxE,MAAM6C,QAAQ,GAAG+B,OAAOpD,KAAKmC,OAAO8C,8BAGtC,qDAAqDjC,GAAG,SAAU1D,QAC5DiF,GAAKjF,EAAE4F,cAAchF,QAAQsE,yBAEzBlF,EAAE6F,OAAOZ,iCACUA,kBACnBlG,SAASsD,sDAA+C4C,iBAAe3C,SAASiD,OACvEA,KAAKnD,WACNmD,KAAKjC,SAAU,yCAIJ2B,mBACnBlG,SAASsD,sDAA+C4C,iBAAe3C,SAASiD,OAC5EA,KAAKjC,SAAU,6BAM7B,gDAAgDI,GAAG,SAAU1D,QACvDiF,GAAKjF,EAAE4F,cAAchF,QAAQ8E,oBAEzB1F,EAAE6F,OAAOZ,4BACKA,kBACdlG,SAASsD,iDAA0C4C,iBAAe3C,SAASiD,OAClEA,KAAKnD,WACNmD,KAAKjC,SAAU,oCAIT2B,mBACdlG,SAASsD,iDAA0C4C,iBAAe3C,SAASiD,OACvEA,KAAKjC,SAAU,6BAM7B,6BAA6BI,GAAG,SAAU1D,WAKhCA,EAAE6F,OAAOZ,QACR,mBACDlG,SAASsD,iBAAiB,wBAAwBC,SAASuC,QAClDA,MAAMzC,WACPyC,MAAMvB,SAAU,gBAKvB,oBACDvE,SAASsD,iBAAiB,wBAAwBC,SAASuC,QACvDA,MAAMvB,SAAU,KAK5BpE,MAAMyG,UAIV5G,SAASsD,iBAAiB,oBAAoBC,SAAQC,MAClDA,IAAIiB,iBAAiB,SAAS,iBACpBsC,KAAOC,SAASrF,KAAKE,QAAQkF,MAC7B/C,KAAOrC,KAAKE,QAAQmC,KACpBiD,KAAOtF,KAAKE,QAAQoF,KACpBC,GAAKvF,KAAKwF,QAAQ,MAElBC,IAAMjH,MAAMkH,OAAOH,IAEzBE,IAAInE,SAAQ,GACZ7D,YAAY4F,KAAK+B,wCACC,gCAAiCO,KAAKC,UAAUnI,oBAG5DoI,UAAqB,eAATP,KAAwB,kBAAoB,iCACxDQ,QAAUzH,SAAS0H,cAAc,UACvCD,QAAQR,KAAO,SACfQ,QAAQ1G,UAAY,iCACpB0G,QAAQE,iEAA4DH,sBAAaxD,MACjFyD,QAAQhD,iBAAiB,SAAS,WAC9B2C,IAAInE,SAAQ,GACZ7D,YAAcA,YAAYyE,QAAOqC,IAAMA,KAAOa,yCAC5B,gCAAiCO,KAAKC,UAAUnI,mBAC7DwI,YAET5H,SAASoD,eAAe,6BAA6ByE,YAAYJ,eA9W7DK,CAAc1I,cACP,KAEV2I,OAAMC,QACH3I,OAAOC,QAAQ0I,MAAM,4BAA6BA"}
